/** UsptStdrChklstDao.insert */
insert into uspt_stdr_chklst
						(
							chklst_id
							, stdr_bsns_cd
							, chklst_cn
							, creator_id
							, created_dt
							, updater_id
							, updated_dt
						)
				values	(
							#{chklstId}
							, #{stdrBsnsCd}
							, #{chklstCn}
							, #{creatorId}
							, #{createdDt}
							, #{updaterId}
							, #{updatedDt}
						)

mapper.update:
/** UsptStdrChklstDao.update */
update uspt_stdr_chklst
set
	chklst_cn = #{chklstCn}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where
	chklst_id = #{chklstId}
	and stdr_bsns_cd = #{stdrBsnsCd}

